// src/core/formatters.js
function parseNumber(input) {
  const raw = typeof input === "string" ? input : input.value;
  return Number.parseFloat(String(raw).replace(",", "."));
}

function formatInputValue(value) {
  return Number.isFinite(value) ? String(value).replace(".", ",") : "";
}

function formatNumber(value, digits = 2) {
  return new Intl.NumberFormat("fr-FR", {
    minimumFractionDigits: 0,
    maximumFractionDigits: digits
  }).format(value);
}

function escapeHtml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll("\"", "&quot;")
    .replaceAll("'", "&#39;");
}

function formatMeters(value, digits = 2) {
  return `${formatNumber(value, digits)} m`;
}

function formatDiameterCm(value) {
  return `${Math.round(value * 100)}`;
}

function formatDiameterCmList(values) {
  return values
    .map((value) => formatDiameterCm(typeof value === "number" ? value : value.diameter))
    .join(", ");
}

function formatSquareMeters(value, digits = 2) {
  return `${formatNumber(value, digits)} m²`;
}

function formatFactor(value, digits = 2) {
  return formatNumber(value, digits);
}

function formatTemp(value, digits = 2) {
  return `${formatNumber(value, digits)} °C`;
}

function formatDb(value, digits = 1) {
  return `${formatNumber(value, digits)} dBA`;
}

function formatWatts(value, digits = 0) {
  return `${formatNumber(value, digits)} W`;
}

function formatDateTime(value = new Date()) {
  return new Intl.DateTimeFormat("fr-FR", {
    dateStyle: "medium",
    timeStyle: "short"
  }).format(value);
}

function formatDiameterList(values) {
  return values.map((diameter) => formatMeters(diameter)).join(", ");
}

function joinWithOr(values) {
  if (values.length <= 1) {
    return values[0] || "";
  }
  if (values.length === 2) {
    return `${values[0]} ou ${values[1]}`;
  }
  return `${values.slice(0, -1).join(", ")} ou ${values[values.length - 1]}`;
}

